#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long prev, cur;
        int M=0;
        long long *distinct = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++){
            scanf("%lld",&cur);
            if(i==0 || cur!=prev){
                distinct[M++] = cur;
                prev = cur;
            }
        }
        printf("%d\n",M);
        for(int i=0;i<M;i++){
            if(i) printf(" ");
            printf("%lld",distinct[i]);
        }
        printf("\n");
        free(distinct);
    }
    return 0;
}

