#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<long long> distinct;
        distinct.reserve(N);
        long long prev, cur;
        for(int i=0;i<N;i++){
            cin>>cur;
            if(i==0 || cur!=prev) distinct.push_back(cur);
            prev=cur;
        }
        cout<<distinct.size()<<'\n';
        for(size_t i=0;i<distinct.size();i++){
            if(i) cout<<' ';
            cout<<distinct[i];
        }
        cout<<'\n';
    }
    return 0;
}

